            Set-Content -Path $vf -Value '{ "name": "demo", "version": "3.4.5" }'
            $r = Read-VersionFile -Path $vf
            $r.Version | Should -Be '3.4.5'
            $r.Format  | Should -Be 'package.json'
        }
        finally { Remove-Item -Recurse -Force $tmp }
    }

