# Pester tests that assert on the GitHub Actions workflow's structure
# (triggers, jobs, step references). These run inside the same act
# container as the unit tests, so the harness validates them via the
# pipeline rather than locally.

BeforeAll {
    $RepoRoot     = Join-Path $PSScriptRoot '..'
    $WorkflowPath = Join-Path $RepoRoot '.github' 'workflows' 'semantic-version-bumper.yml'

    # Lightweight YAML reader: install powershell-yaml on demand and use that.
    if (-not (Get-Module -ListAvailable powershell-yaml)) {
        try {
            Install-Module -Name powershell-yaml -Scope CurrentUser -Force -AcceptLicense -ErrorAction Stop
        }
        catch {
            # Containers with no network: fall back to a regex sniff in each test.
            $script:UseYamlModule = $false
            return
        }
    }
    Import-Module powershell-yaml -ErrorAction Stop
    $script:UseYamlModule = $true
    $script:Workflow      = ConvertFrom-Yaml (Get-Content -Raw $WorkflowPath)
}

Describe 'workflow file' {
    It 'exists at the canonical path' {
        $RepoRoot     = Join-Path $PSScriptRoot '..'
        $WorkflowPath = Join-Path $RepoRoot '.github' 'workflows' 'semantic-version-bumper.yml'
        Test-Path $WorkflowPath | Should -BeTrue
    }

    It 'declares all four trigger events' -Skip:(-not $script:UseYamlModule) {
        # 'on' is reserved in YAML 1.1 — powershell-yaml maps it to $true. Try both.
        $on = $script:Workflow['on']
        if ($null -eq $on) { $on = $script:Workflow[$true] }
        $on.Keys | Should -Contain 'push'
        $on.Keys | Should -Contain 'pull_request'
        $on.Keys | Should -Contain 'workflow_dispatch'
        $on.Keys | Should -Contain 'schedule'
    }

    It 'has both unit-tests and bump-version jobs' -Skip:(-not $script:UseYamlModule) {
        $script:Workflow.jobs.Keys | Should -Contain 'unit-tests'
        $script:Workflow.jobs.Keys | Should -Contain 'bump-version'
    }

    It 'orders bump-version after unit-tests via needs' -Skip:(-not $script:UseYamlModule) {
        $script:Workflow.jobs['bump-version'].needs | Should -Be 'unit-tests'
    }

    It 'sets pwsh as the default shell' -Skip:(-not $script:UseYamlModule) {
        $script:Workflow.defaults.run.shell | Should -Be 'pwsh'
    }

    It 'references the bump-version.ps1 script that exists on disk' {
        $RepoRoot = Join-Path $PSScriptRoot '..'
        $script   = Join-Path $RepoRoot 'src' 'bump-version.ps1'
        Test-Path $script | Should -BeTrue

        # Whether or not the YAML module loaded, prove the path is mentioned.
        $WorkflowPath = Join-Path $RepoRoot '.github' 'workflows' 'semantic-version-bumper.yml'
        (Get-Content -Raw $WorkflowPath) | Should -Match 'src/bump-version\.ps1'
    }

    It 'references the SemverBumper module that exists on disk' {
        $RepoRoot = Join-Path $PSScriptRoot '..'
        $module   = Join-Path $RepoRoot 'src' 'SemverBumper.psm1'
        Test-Path $module | Should -BeTrue
    }

    It 'requires least-privilege contents:read permissions' -Skip:(-not $script:UseYamlModule) {
        $script:Workflow.permissions.contents | Should -Be 'read'
    }

    It 'pins all action references to a major version (no "@main")' {
        $RepoRoot     = Join-Path $PSScriptRoot '..'
        $WorkflowPath = Join-Path $RepoRoot '.github' 'workflows' 'semantic-version-bumper.yml'
        $content      = Get-Content -Raw $WorkflowPath
        $content | Should -Not -Match 'uses:\s*\S+@main\b'
        $content | Should -Not -Match 'uses:\s*\S+@master\b'
    }
}

